{
  "type": "QUIZ",
  "lessonText": "Test your knowledge on the basics of Python for game development.",
  "data": {
    "questions": [
      {
        "question": "What is the correct way to declare a variable in Python?",
        "options": [
          "var x = 10",
          "x := 10",
          "x = 10",
          "10 = x"
        ],
        "correctAnswer": 2,
        "explanation": "In Python, variables are declared using the '=' operator."
      },
      {
        "question": "Which of the following is a valid Python list?",
        "options": [
          "[1, 2, 3]",
          "(1, 2, 3)",
          "{1, 2, 3}",
          "<1, 2, 3>"
        ],
        "correctAnswer": 0,
        "explanation": "Lists in Python are defined using square brackets."
      },
      {
        "question": "What keyword is used to define a function in Python?",
        "options": [
          "function",
          "def",
          "func",
          "define"
        ],
        "correctAnswer": 1,
        "explanation": "Functions in Python are defined using the 'def' keyword."
      },
      {
        "question": "Which of the following is a comment in Python?",
        "options": [
          "// This is a comment",
          "# This is a comment",
          "<!-- This is a comment -->",
          "/* This is a comment */"
        ],
        "correctAnswer": 1,
        "explanation": "In Python, comments are written using the '#' symbol."
      }
    ]
  }
}
